$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_ad95726b35cf144d5058b37d48e6c140'] = 'Dies ist normalerweise bezogen auf die Nutzung von AdBlocks, leider kann das Modul nicht in dieser Situation tun';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_cc0445f72b30759cb53c6b82db294014'] = 'Auch ein Zahlungsmodul, welches eine zwischenliegende  Seite könnte dies verursachen. In diesem Fall musst du nur die erweiterte Option aktivieren ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_24e8ac50b8118374d041f62912a4d850'] = 'Duplikate Kauf Events:';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_de62e22ac415d3eb9240b1023175b855'] = 'Diese wird normalerweise von Cache Engines verursacht wie nicht heimische Cache Module oder dritte Parteien Software wie CloudFlare.';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_4e15b0b357e2427f306fd8f61e1a56dc'] = 'Standardmäßig verlässt sich das Modul nicht auf die Danke schön Seite für das Kauf Event, dies macht es kompatibel mit jedem Zahlungsmodul, egal welche zurück kommende Seite angezeigt wird nach der Zahlung, aber die Cache Engines cashen das Output des Moduls, und zwingt es zu wiederholen selbst wenn unnötig. ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_53f0d8f2e081eb6375416a5331275d5a'] = 'Wenn dies passiert, aktiviere die erweiterte Option ';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_5d167d92ce03c8db70da784b1b5001b4'] = 'Aber manche Caches sind  sehr schwer und könnten die drei Überprüfungen des angewandten Moduls ignorieren';
$_MODULE['<{facebookconversiontrackingplus}prestashop>faq-answers_f7cee7aa810ddefb08c52bd6693b39c5'] = 'Natürlich! Facebook Pixel wird auf dem Seitenkopf initialisiert, dies bedeutet du kann ein Event auslösen (senden) über jede Seite. Dies ist nützlich wenn du ein Lead Event hast, zum Beispiel indem du es an eine bestimmte Tasten Klick verbindest ';
